import functools

def logger(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        print(f'Calling: {func.__name__}({args})')
        result = func(*args, **kwargs)
        print(f'Returned: {result}')
        return result
    return wrapper

@logger
def add(a, b):
    return a + b

result = add(3, 5)
print(f'Final: {result}')

