import functools
def cache(func):
    _cache = {}
    @functools.wraps(func)
    def wrapper(*args):
        if args in _cache:
            return _cache[args]
        result = func(*args)
        _cache[args] = result
        return result
    return wrapper
@cache
def fibonacci(n):
    if n < 2: return n
    return fibonacci(n-1) + fibonacci(n-2)
assert fibonacci(10) == 55
assert fibonacci(20) == 6765
assert fibonacci(10) == 55
